Here's how to test your `DataFetcher` using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        // Act
        var result = await _sut.FetchAsync("https://example.com/data",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.StatusCode = HttpStatusCode.NotFound;

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync("https://example.com/missing",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        _handler.ResponseContent = "fast";
        _handler.StatusCode = HttpStatusCode.OK;

        // TestContext.CancellationToken is cancelled when [Timeout] expires
        var result = await _sut.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }
}
```

**The mock handler:**

```csharp
internal sealed class MockHttpMessageHandler : HttpMessageHandler
{
    public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
    public string ResponseContent { get; set; } = string.Empty;

    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();

        var response = new HttpResponseMessage(StatusCode)
        {
            Content = new StringContent(ResponseContent)
        };
        return Task.FromResult(response);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | Return `Task`, use `async`/`await` directly |
| Timeouts | `[Timeout(ms)]` + pass `_testContext.CancellationToken` |
| Cancellation | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| Exception testing | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| HttpClient mocking | Custom `HttpMessageHandler` — no third-party mocking library needed |
| Lifecycle | Constructor injection of `TestContext` for `readonly` fields |

The critical insight: `[Timeout]` cancels `TestContext.CancellationToken` when time expires, so always pass it through to your async calls. This gives you real deadline enforcement rather than just a test-runner kill switch.
